test_that("ci_tree rejects negative weights", {
  toy_data <- data.frame(
    rank = c(10, 20, 30, 40),
    outcome = c(1, 0, 1, 0),
    income = c(2, 4, 6, 8)
  )

  expect_error(
    ci_tree(
      formula = cbind(rank, outcome) ~ income,
      data = toy_data,
