test_that("ci_tree rejects non-finite weights", {
  toy_data <- data.frame(
    rank = c(10, 20, 30),
    outcome = c(1, 0, 1),
    income = c(2, 4, 6)
  )

  for (bad_weights in list(c(1, Inf, 1), c(1, NaN, 1), c(1, -Inf, 1))) {
    expect_error(
      ci_tree(
        formula = cbind(rank, outcome) ~ income,
        data = toy_data,
        rank_name = "rank",
        outcome_name = "outcome",
        weights = bad_weights
      ),
      "finite"
    )
  }
})

