})

test_that("ci_tree stores simple rpart-style variable importance", {
  toy_data <- data.frame(
    rank = c(10, 20, 30, 40, 50, 60),
    outcome = c(1, 0, 1, 0, 1, 1),
    income = c(2, 4, 6, 8, 10, 12),
    group = factor(c("low", "low", "mid", "mid", "high", "high"))
  )

  fit <- ci_tree(
    formula = cbind(rank, outcome) ~ income + group,
    data = toy_data,
    rank_name = "rank",
    outcome_name = "outcome",
    control = ci_tree_control(minsplit = 1, minbucket = 1, maxdepth = 2)
  )

  expect_type(fit$variable.importance, "double")
  expect_named(fit$variable.importance)
  expect_gt(length(fit$variable.importance), 0L)
  expect_true(all(fit$variable.importance >= 0))
  expect_equal(
    fit$variable.importance,
    sort(fit$variable.importance, decreasing = TRUE)
  )
})

test_that("ci_tree split_engine R fallback matches cpp default", {
  toy_data <- data.frame(
    rank = c(10, 20, 30, 40, 50, 60, 70, 80),
    outcome = c(1, 0, 1, 0, 1, 1, 0, 1),
    income = c(2, 4, 6, 8, 10, 12, 14, 16),
    group = factor(c("low", "low", "mid", "mid", "high", "high", "top", "top"))
  )

  ctrl_cpp <- ci_tree_control(
    minsplit = 1,
    minbucket = 1,
    maxdepth = 2,
    split_engine = "cpp"
  )
  ctrl_r <- ci_tree_control(
    minsplit = 1,
    minbucket = 1,
    maxdepth = 2,
    split_engine = "R"
  )

  fit_cpp <- ci_tree(
    formula = cbind(rank, outcome) ~ income + group,
    data = toy_data,
    rank_name = "rank",
    outcome_name = "outcome",
    control = ctrl_cpp
  )
  fit_r <- ci_tree(
    formula = cbind(rank, outcome) ~ income + group,
    data = toy_data,
    rank_name = "rank",
    outcome_name = "outcome",
    control = ctrl_r
  )

  expect_equal(stats::predict(fit_cpp, type = "node"), stats::predict(fit_r, type = "node"))
  expect_equal(fit_cpp$info$control$split_engine, "cpp")
  expect_equal(fit_r$info$control$split_engine, "R")
})

